/**
 * PDF to Images Converter
 * Converte documentos PDF em imagens por página usando pdftoppm (poppler-utils)
 *
 * Cada página do PDF é renderizada como uma imagem PNG ou JPEG individual,
 * preservando a sequência original das páginas.
 */

import { execFile } from 'child_process';
import { promisify } from 'util';
import { promises as fs } from 'fs';
import * as path from 'path';
import { logger } from '@lib/logger';

const execFileAsync = promisify(execFile);

export interface PageImage {
  pageNumber: number;
  imagePath: string;
  width: number;
  height: number;
}

export interface PdfConversionResult {
  success: boolean;
  images: PageImage[];
  totalPages: number;
  error?: string;
}

export interface PdfConversionOptions {
  /** Output image width in pixels (default: 1920) */
  width?: number;
  /** Output image height in pixels (default: 1080) */
  height?: number;
  /** DPI for rendering (default: 150) */
  dpi?: number;
  /** Output format: 'png' or 'jpeg' (default: 'png') */
  format?: 'png' | 'jpeg';
  /** Custom output directory (auto-created if not exists) */
  outputDir?: string;
  /** Timeout in ms (default: 120000) */
  timeoutMs?: number;
  /** First page to convert (1-based, default: 1) */
  firstPage?: number;
  /** Last page to convert (default: all pages) */
  lastPage?: number;
}

const DEFAULT_OPTIONS: Required<Omit<PdfConversionOptions, 'firstPage' | 'lastPage'>> = {
  width: 1920,
  height: 1080,
  dpi: 150,
  format: 'png',
  outputDir: '',
  timeoutMs: 120_000,
};

/**
 * Verifica se pdftoppm está disponível no PATH
 */
async function isPdftoppmAvailable(): Promise<boolean> {
  try {
    await execFileAsync('which', ['pdftoppm']);
    return true;
  } catch {
    return false;
  }
}

/**
 * Conta o número de páginas de um PDF usando pdfinfo (poppler-utils)
 */
async function getPdfPageCount(pdfPath: string): Promise<number | null> {
  try {
    const { stdout } = await execFileAsync('pdfinfo', [pdfPath], { timeout: 10_000 });
    const match = stdout.match(/Pages:\s+(\d+)/);
    return match ? parseInt(match[1], 10) : null;
  } catch {
    // pdfinfo might not be available
    return null;
  }
}

/**
 * Converte um arquivo PDF em imagens, uma por página, preservando a sequência.
 *
 * Requer pdftoppm (poppler-utils) instalado no sistema.
 *
 * @param pdfPath - Caminho absoluto do arquivo PDF
 * @param options - Opções de conversão
 * @returns Resultado com array de imagens ordenadas por página
 */
export async function convertPdfToImages(
  pdfPath: string,
  options?: PdfConversionOptions
): Promise<PdfConversionResult> {
  const opts = { ...DEFAULT_OPTIONS, ...options };

  // Validate input file
  try {
    await fs.access(pdfPath);
  } catch {
    return {
      success: false,
      images: [],
      totalPages: 0,
      error: `Input file not found: ${pdfPath}`,
    };
  }

  // Check pdftoppm availability
  const hasPdftoppm = await isPdftoppmAvailable();
  if (!hasPdftoppm) {
    logger.error('[PDF→Images] pdftoppm not found in PATH', new Error('pdftoppm not installed'), {
      component: 'PDFToImages',
    });
    return {
      success: false,
      images: [],
      totalPages: 0,
      error:
        'pdftoppm (poppler-utils) is not installed. Install with: apt-get install poppler-utils (Debian/Ubuntu) or brew install poppler (macOS)',
    };
  }

  // Create output directory
  const outputDir =
    opts.outputDir || path.join(path.dirname(pdfPath), `pages_${Date.now()}`);
  await fs.mkdir(outputDir, { recursive: true });

  try {
    // Get page count for comparison later
    const expectedPages = await getPdfPageCount(pdfPath);

    // Build pdftoppm args
    const outputPrefix = path.join(outputDir, 'page');
    const formatFlag = opts.format === 'jpeg' ? '-jpeg' : '-png';

    const args: string[] = [
      formatFlag,
      '-r', String(opts.dpi),
      '-scale-to-x', String(opts.width),
      '-scale-to-y', String(opts.height),
    ];

    // Page range options
    if (options?.firstPage) {
      args.push('-f', String(options.firstPage));
    }
    if (options?.lastPage) {
      args.push('-l', String(options.lastPage));
    }

    args.push(pdfPath, outputPrefix);

    logger.info('[PDF→Images] Converting PDF to images via pdftoppm', {
      component: 'PDFToImages',
      dpi: opts.dpi,
      format: opts.format,
      width: opts.width,
      height: opts.height,
      expectedPages,
    });

    await execFileAsync('pdftoppm', args, {
      timeout: opts.timeoutMs,
      maxBuffer: 10 * 1024 * 1024,
    });

    // Read generated files, sorted by page number
    const ext = opts.format === 'jpeg' ? 'jpg' : 'png';
    const files = await fs.readdir(outputDir);
    const imageFiles = files
      .filter(f => f.startsWith('page-') && f.endsWith(`.${ext}`))
      .sort((a, b) => {
        const numA = parseInt(a.replace(/\D/g, ''), 10);
        const numB = parseInt(b.replace(/\D/g, ''), 10);
        return numA - numB;
      });

    if (imageFiles.length === 0) {
      return {
        success: false,
        images: [],
        totalPages: 0,
        error: 'No page images were generated. The PDF may be empty or corrupted.',
      };
    }

    const images: PageImage[] = imageFiles.map((imgFile, index) => ({
      pageNumber: index + 1,
      imagePath: path.join(outputDir, imgFile),
      width: opts.width,
      height: opts.height,
    }));

    // Compare with expected page count
    if (expectedPages !== null && images.length !== expectedPages) {
      logger.warn('[PDF→Images] Generated image count differs from expected page count', {
        component: 'PDFToImages',
        expected: expectedPages,
        generated: images.length,
      });
    }

    logger.info('[PDF→Images] Conversion complete', {
      component: 'PDFToImages',
      totalPages: images.length,
      expectedPages,
      outputDir,
    });

    return {
      success: true,
      images,
      totalPages: images.length,
    };
  } catch (error: unknown) {
    const errorMessage = error instanceof Error ? error.message : String(error);
    logger.error('[PDF→Images] Conversion failed', error instanceof Error ? error : new Error(errorMessage), {
      component: 'PDFToImages',
      input: path.basename(pdfPath),
    });

    return {
      success: false,
      images: [],
      totalPages: 0,
      error: errorMessage,
    };
  }
}

/**
 * Verifica se o sistema tem pdftoppm para conversão de PDFs
 */
export async function checkPdfDependencies(): Promise<{
  pdftoppm: boolean;
  pdfinfo: boolean;
  ready: boolean;
  message: string;
}> {
  const pdftoppm = await isPdftoppmAvailable();
  let pdfinfo = false;
  try {
    await execFileAsync('which', ['pdfinfo']);
    pdfinfo = true;
  } catch {
    pdfinfo = false;
  }

  const ready = pdftoppm;
  let message = 'PDF conversion dependencies available';
  if (!ready) {
    message = 'Missing pdftoppm (poppler-utils). Install with: apt-get install poppler-utils';
  }

  return { pdftoppm, pdfinfo, ready, message };
}
